const proj = $input.first().json;
const pid = proj.id;
if (!pid) return [];
return [{ json: { project: proj, project_id: pid, chapter_count: 0, plot_thread_count: 0 } }];

// Build the weekly planning prompt using all loaded context
const project = $('Load Active Project').first().json;
const stateResults = $('Load Project State').all();

// Parse multi-statement results
let recentChapters = [];
let plotThreads = [];
let foreshadowing = [];
let existingPlans = [];
let readerFeedback = [];
let stats = {};

for (const item of stateResults) {
  const j = item.json;
  if (j.sequence && j.summary) recentChapters.push(j);
  else if (j.thread_type) plotThreads.push(j);
  else if (j.clue_text) foreshadowing.push(j);
  else if (j.plot_goals) existingPlans.push(j);
  else if (j.feedback_text || j.sentiment) readerFeedback.push(j);
  else if (j.total_planned !== undefined) stats = j;
}

// Determine last planned sequence
const maxPlannedSeq = existingPlans.length > 0
  ? Math.max(...existingPlans.map(p => p.sequence))
  : recentChapters.length > 0
    ? Math.max(...recentChapters.map(c => c.sequence))
    : 0;

return [{
  json: {
    project: project,
    recent_chapters: recentChapters,
    active_plot_threads: plotThreads,
    unresolved_foreshadowing: foreshadowing,
    existing_plans: existingPlans,
    reader_feedback: readerFeedback,
    stats: stats,
    next_sequence_start: maxPlannedSeq + 1,
    chapters_to_plan: 10
  }
}];

const response = $input.first().json;
let rawText = "";

if (response.message && response.message.content) {
  rawText = response.message.content;
} else if (response.choices && response.choices[0] && response.choices[0].message) {
  rawText = response.choices[0].message.content;
} else if (typeof response === "string") {
  rawText = response;
} else {
  rawText = JSON.stringify(response);
}

rawText = rawText.trim();
if (rawText.startsWith("```")) {
  var nl = rawText.indexOf("\n");
  if (nl >= 0) rawText = rawText.substring(nl + 1);
}
if (rawText.endsWith("```")) {
  rawText = rawText.substring(0, rawText.length - 3).trim();
}

let plan;
try {
  plan = JSON.parse(rawText);
} catch (e) {
  throw new Error("Failed to parse arc plan. Raw (first 300): " + rawText.substring(0, 300));
}

const projectId = $("Load Active Project").first().json.id;
const context = $("Build Planning Context").first().json;

return [{
  json: {
    project_id: projectId,
    plan: plan,
    next_sequence_start: context.next_sequence_start,
    has_human_review: (plan.human_review_required || []).length > 0
  }
}];

var data = $input.first().json;
var plan = data.plan;
var pid = data.project_id;
var items = [];

function esc(val) {
  if (val === undefined || val === null) return "NULL";
  if (typeof val === "boolean") return val ? "TRUE" : "FALSE";
  if (typeof val === "number") return String(val);
  var str = typeof val === "object" ? JSON.stringify(val) : String(val);
  return "'" + str.replace(/'/g, "''") + "'";
}

var plans = plan.chapter_plans || plan.new_chapter_plans || plan.chapters || [];

for (var i = 0; i < plans.length; i++) {
  var cp = plans[i];
  var seq = (data.next_sequence_start || 1) + i;
  var sql = "INSERT INTO chapter_plans (project_id, sequence, title, plot_goals, outline, target_word_count, status) VALUES ("
    + esc(pid) + ", " + esc(seq) + ", "
    + esc(cp.title || ("Chapter " + seq)) + ", "
    + esc(cp.plot_goals || []) + ", "
    + esc(cp.summary || cp.outline || "") + ", "
    + esc(cp.target_word_count || 3000) + ", "
    + esc("planned")
  + ") RETURNING id";
  items.push({ json: { sql: sql } });
}

if (items.length === 0) {
  items.push({ json: { sql: "SELECT 1 AS note", _info: "No chapters in plan" } });
}

return items;

const data = $('Parse Arc Plan').first().json;
const plan = data.plan;

return [{
  json: {
    project_id: data.project_id,
    chapters_planned: (plan.new_chapter_plans || []).length,
    plot_threads_updated: (plan.plot_thread_updates || []).length,
    foreshadowing_updated: (plan.foreshadowing_updates || []).length,
    human_review_count: (plan.human_review_required || []).length,
    human_review_items: plan.human_review_required || [],
    weekly_summary: plan.weekly_summary || '',
    pacing_analysis: plan.weekly_analysis?.current_pacing || '',
    status: 'weekly_plan_complete'
  }
}];
